import React, { useState } from "react";
import axios from "axios";

function App() {
  const [formData, setFormData] = useState({
    data_atividade: "",
    supervisor: "",
    status: "",
    eletricista_motorista: "",
    eletricista_parceiro: "",
    equipe: "",
    servico: "",
    placa_veiculo: "",
  });

  const [teams, setTeams] = useState([]);
  const [editId, setEditId] = useState(null);

  const fetchTeams = async () => {
    try {
      console.log("Data enviada para o backend:", formData.data_atividade); // Debug
      const response = await axios.get("http://localhost:5000/teams", {
        params: {
          data: formData.data_atividade,
          finalizado: true, // Busca apenas registros finalizados
        },
      });
      console.log("Dados recebidos do backend:", response.data); // Debug
      setTeams(response.data);
    } catch (error) {
      console.error("Erro ao buscar equipes finalizadas:", error);
    }
  };


  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editId) {
        await axios.put(`http://localhost:5000/teams/${editId}`, formData);
        setEditId(null);
      } else {
        const response = await axios.post("http://localhost:5000/teams", formData);
        setTeams((prevTeams) => [...prevTeams, response.data]); // Adiciona na exibição
      }

      setFormData({
        data_atividade: "",
        supervisor: "",
        status: "",
        eletricista_motorista: "",
        eletricista_parceiro: "",
        equipe: "",
        servico: "",
        placa_veiculo: "",
      });

      fetchTeamsAtivas(); // Atualiza a exibição com os registros ativos
    } catch (error) {
      alert(error.response?.data?.message || "Erro ao cadastrar equipe.");
    }
  };



  const handleEdit = (team) => {
    setFormData(team);
    setEditId(team.id);
  };

  const handleDelete = async (id) => {
    if (window.confirm("Tem certeza que deseja excluir este registro?")) {
      try {
        await axios.delete(`http://localhost:5000/teams/${id}`);
        fetchTeams(); // Atualiza a tabela após exclusão
      } catch (error) {
        console.error("Erro ao excluir equipe:", error);
      }
    }
  };

  const handleFinalizar = async () => {
    if (window.confirm("Confirma que todos os registros estão revisados? Isso limpará a tela.")) {
      try {
        await axios.put("http://localhost:5000/teams/finalizar");
        setTeams([]);
        setFormData({
          data_atividade: "",
          supervisor: "",
          status: "",
          eletricista_motorista: "",
          eletricista_parceiro: "",
          equipe: "",
          servico: "",
          placa_veiculo: "",
        });
        alert("Registros finalizados com sucesso!");
      } catch (error) {
        console.error("Erro ao finalizar registros:", error);
        alert("Erro ao finalizar registros.");
      }
    }
  };

  return (
    <div className="p-6 max-w-6xl mx-auto bg-white shadow-lg rounded-lg mt-10">
      <h1 className="text-3xl font-semibold text-gray-700 text-center mb-6">
        Cadastro de Equipes
      </h1>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <input
            type="date"
            name="data_atividade"
            value={formData.data_atividade}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          />
          <select
            name="supervisor"
            value={formData.supervisor}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione o(a) Supervisor(a)</option>
            <option value="0000-JOAO">0000-JOAO</option>
            <option value="1111-PEDRO">1111-PEDRO</option>
            <option value="2222-ANA">2222-ANA</option>
          </select>
        </div>
        <div className="grid grid-cols-2 gap-4">
          <select
            name="status"
            value={formData.status}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Status</option>
            <option value="ATESTADO">ATESTADO</option>
            <option value="CAMPO">CAMPO</option>
          </select>
          <select
            name="equipe"
            value={formData.equipe}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Equipe</option>
            <option value="CEN001">CEN001</option>
            <option value="CEN002">CEN002</option>
          </select>
        </div>
        <div className="grid grid-cols-2 gap-4">
          <select
            name="eletricista_motorista"
            value={formData.eletricista_motorista}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Eletricista Motorista</option>
            <option value="1212 - JOAO">1212 - JOAO</option>
            <option value="1111 - MARIA">1111 - MARIA</option>
          </select>
          <select
            name="eletricista_parceiro"
            value={formData.eletricista_parceiro}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Eletricista Parceiro(a)</option>
            <option value="1212 - JOAO">1212 - JOAO</option>
            <option value="1111 - MARIA">1111 - MARIA</option>
          </select>
        </div>
        <div className="grid grid-cols-2 gap-4">
          <select
            name="servico"
            value={formData.servico}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Servico</option>
            <option value="LIGACAO NOVA">LIGACAO NOVA</option>
            <option value="CORTE">CORTE</option>
          </select>
          <select
            name="placa_veiculo"
            value={formData.placa_veiculo}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Placa</option>
            <option value="SRV - 2356">SRV - 2356</option>
            <option value="AFX - 8975">AFX - 8975</option>
          </select>
        </div>
        <button type="submit" className="w-full bg-blue-600 text-white p-2 rounded-md hover:bg-blue-700">
          {editId ? "Atualizar" : "Cadastrar"}
        </button>
      </form>

      <button
        onClick={fetchTeams}
        className="mt-4 w-full bg-purple-600 text-white p-2 rounded-md hover:bg-purple-700"
      >
        Buscar Equipes
      </button>

      <h2 className="text-xl font-semibold text-gray-700 mt-6">Equipes Cadastradas</h2>
      <div className="overflow-x-auto mt-3">
        <table className="min-w-full bg-white border rounded-lg">
          <thead>
            <tr className="bg-gray-200 text-gray-700 text-sm">
              <th className="p-2 border">Data</th>
              <th className="p-2 border w-56">Supervisor(a)</th>
              <th className="p-2 border">Status</th>
              <th className="p-2 border">Equipe</th>
              <th className="p-2 border">Eletricista Motorista</th>
              <th className="p-2 border">Eletricista Parceiro(a)</th>
              <th className="p-2 border">Serviço</th>
              <th className="p-2 border">Placa</th>
              <th className="p-2 border">Ações</th>
            </tr>
          </thead>
          <tbody className="text-sm">
            {teams.map((team) => (
              <tr key={team.id} className="text-center">
                <td className="p-2 border">{team.data_atividade}</td>
                <td className="p-2 border">{team.supervisor}</td>
                <td className="p-2 border">{team.status}</td>
                <td className="p-2 border">{team.equipe}</td>
                <td className="p-2 border">{team.eletricista_motorista}</td>
                <td className="p-2 border">{team.eletricista_parceiro}</td>
                <td className="p-2 border">{team.servico}</td>
                <td className="p-2 border">{team.placa_veiculo}</td>
                <td className="p-2 border flex gap-2 justify-center">
                  <button onClick={() => handleEdit(team)} className="bg-yellow-500 text-white px-3 py-1 rounded-md hover:bg-yellow-600">
                    Editar
                  </button>
                  <button onClick={() => handleDelete(team.id)} className="bg-red-500 text-white px-3 py-1 rounded-md hover:bg-red-600">
                    Excluir
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <button onClick={handleFinalizar} className="mt-4 w-full bg-green-600 text-white p-2 rounded-md hover:bg-green-700">
        Finalizar
      </button>
    </div>
  );
}

export default App;
